import React, { useState } from 'react';
import { useBlockchain } from '../context/BlockchainContext';

const AdminDashboard: React.FC = () => {
    const { isAdmin, contract } = useBlockchain();

    // Verifier State
    const [verifierAddress, setVerifierAddress] = useState('');

    // Entity State
    const [entityAddress, setEntityAddress] = useState('');
    const [entityName, setEntityName] = useState('');
    const [entityType, setEntityType] = useState('0'); // Default to BANK
    const [entityEndpoint, setEntityEndpoint] = useState('');

    const [applications, setApplications] = useState<any[]>([]);
    const [loading, setLoading] = useState(false);
    const [message, setMessage] = useState('');

    React.useEffect(() => {
        if (isAdmin) fetchApplications();
    }, [isAdmin]);

    const fetchApplications = async () => {
        try {
            const token = localStorage.getItem('token');
            const res = await fetch('http://localhost:5000/api/entity/applications', {
                headers: { 'x-auth-token': token || '' }
            });
            const data = await res.json();
            if (res.ok) setApplications(data);
        } catch (err) {
            console.error(err);
        }
    };

    const approveApplication = async (app: any) => {
        if (!contract) return;
        setLoading(true);
        setMessage('');
        try {
            // 1. Blockchain Transaction
            const tx = await contract.registerEntity(
                app.walletAddress,
                app.onChainType,
                app.entityName || app.fullName,
                app.apiEndpoint || 'N/A'
            );
            await tx.wait();

            // 2. Backend DB Update
            const token = localStorage.getItem('token');
            await fetch('http://localhost:5000/api/entity/approve-application', {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    'x-auth-token': token || ''
                },
                body: JSON.stringify({ userId: app._id })
            });

            setMessage(`Success: ${app.entityName} is now whitelisted on-chain.`);
            fetchApplications();
        } catch (error: any) {
            setMessage(`Protocol Error: ${error.message}`);
        } finally {
            setLoading(false);
        }
    };

    const rejectApplication = async (userId: string) => {
        setLoading(true);
        try {
            const token = localStorage.getItem('token');
            await fetch('http://localhost:5000/api/entity/reject-application', {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    'x-auth-token': token || ''
                },
                body: JSON.stringify({ userId })
            });
            fetchApplications();
        } catch (err) {
            console.error(err);
        } finally {
            setLoading(false);
        }
    };

    if (!isAdmin) {
        return (
            <div className="glass fade-in" style={{ padding: '6rem 3rem', textAlign: 'center', marginTop: '4rem' }}>
                <div style={{ fontSize: '3rem', marginBottom: '1.5rem', color: 'var(--error)' }}>⚠</div>
                <h2 style={{ fontSize: '2rem' }}>Access Denied</h2>
                <p>Only the protocol administrator can access this management portal.</p>
            </div>
        );
    }

    const handleVerifierAction = async (action: 'add' | 'remove') => {
        if (!contract || !verifierAddress) return;
        setLoading(true);
        setMessage('');
        try {
            const tx = action === 'add' 
                ? await contract.addVerifier(verifierAddress) 
                : await contract.removeVerifier(verifierAddress);
            await tx.wait();
            setMessage(`Protocol Updated: Successfully ${action === 'add' ? 'authorized' : 'revoked'} verifier.`);
            setVerifierAddress('');
        } catch (error: any) {
            setMessage(`Protocol Error: ${error.reason || error.message || 'Operation failed'}`);
        } finally {
            setLoading(false);
        }
    };

    const handleRegisterEntity = async () => {
        if (!contract || !entityAddress || !entityName) return;
        setLoading(true);
        setMessage('');
        try {
            const tx = await contract.registerEntity(
                entityAddress,
                parseInt(entityType),
                entityName,
                entityEndpoint || 'N/A'
            );
            await tx.wait();
            setMessage(`Protocol Updated: '${entityName}' registered as authorized entity.`);
            setEntityAddress('');
            setEntityName('');
            setEntityEndpoint('');
        } catch (error: any) {
            setMessage(`Protocol Error: ${error.reason || error.message || 'Entity registration failed'}`);
        } finally {
            setLoading(false);
        }
    };

    const handleRemoveEntity = async () => {
        if (!contract || !entityAddress) return;
        setLoading(true);
        setMessage('');
        try {
            const tx = await contract.removeEntity(entityAddress);
            await tx.wait();
            setMessage(`Protocol Updated: Entity at ${entityAddress.slice(0, 10)}... removed.`);
            setEntityAddress('');
        } catch (error: any) {
            setMessage(`Protocol Error: ${error.reason || error.message || 'Entity removal failed'}`);
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="fade-in" style={{ maxWidth: '1000px', margin: '0 auto' }}>
            <div style={{ marginBottom: '4rem' }}>
                <h1 style={{ fontSize: '3.5rem' }}>Network Administration</h1>
                <p style={{ fontSize: '1.2rem', color: 'var(--text-secondary)' }}>Protocol Governance & Multi-Entity Registry</p>
            </div>

            {message && (
                <div className="glass" style={{ 
                    padding: '1.5rem', 
                    marginBottom: '3rem', 
                    background: message.includes('Error') ? 'rgba(255,68,68,0.05)' : 'rgba(0,255,136,0.05)',
                    borderLeft: `6px solid ${message.includes('Error') ? 'var(--error)' : 'var(--success)'}`,
                    color: message.includes('Error') ? 'var(--error)' : 'var(--success)',
                    fontWeight: 600
                }}>
                    {message}
                </div>
            )}

            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '2.5rem' }}>
                {/* Entity Registry Form */}
                <div className="glass" style={{ padding: '2.5rem' }}>
                    <h3 style={{ marginBottom: '2rem', borderLeft: '4px solid #fff', paddingLeft: '1rem' }}>Entity Registry</h3>
                    <div style={{ display: 'flex', flexDirection: 'column', gap: '1.5rem' }}>
                        <div>
                            <label>Institution Wallet</label>
                            <input 
                                type="text" 
                                value={entityAddress}
                                onChange={(e) => setEntityAddress(e.target.value)}
                                placeholder="0x..."
                            />
                        </div>
                        <div>
                            <label>Legal Entity Name</label>
                            <input 
                                type="text" 
                                value={entityName}
                                onChange={(e) => setEntityName(e.target.value)}
                                placeholder="e.g. HDFC Bank"
                            />
                        </div>
                        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1rem' }}>
                            <div>
                                <label>Registry Type</label>
                                <select value={entityType} onChange={(e) => setEntityType(e.target.value)} style={{ width: '100%', padding: '1rem', background: 'rgba(255,255,255,0.05)', border: '1px solid var(--card-border)', color: '#fff' }}>
                                    <option value="0">Bank</option>
                                    <option value="1">Crypto Exchange</option>
                                    <option value="2">Insurance</option>
                                    <option value="3">Government</option>
                                    <option value="5">DeFi Portal</option>
                                    <option value="7">Other</option>
                                </select>
                            </div>
                            <div>
                                <label>API Endpoint</label>
                                <input 
                                    type="text" 
                                    value={entityEndpoint}
                                    onChange={(e) => setEntityEndpoint(e.target.value)}
                                    placeholder="https://..."
                                />
                            </div>
                        </div>
                        <div style={{ display: 'flex', gap: '1rem', marginTop: '1rem' }}>
                            <button onClick={handleRegisterEntity} disabled={loading || !entityAddress} className="btn btn-primary" style={{ flex: 1 }}>
                                {loading ? 'Wait...' : 'Whitelist Entity'}
                            </button>
                            <button onClick={handleRemoveEntity} disabled={loading || !entityAddress} className="btn btn-outline" style={{ flex: 0.5, borderColor: 'var(--error)', color: 'var(--error)' }}>
                                Remove
                            </button>
                        </div>
                    </div>
                </div>

                {/* Verifier Management */}
                <div className="glass" style={{ padding: '2.5rem' }}>
                    <h3 style={{ marginBottom: '2rem', borderLeft: '4px solid #fff', paddingLeft: '1rem' }}>Nodes & Verifiers</h3>
                    <div style={{ display: 'flex', flexDirection: 'column', gap: '1.5rem' }}>
                        <div>
                            <label>Node Wallet Address</label>
                            <input 
                                type="text" 
                                value={verifierAddress}
                                onChange={(e) => setVerifierAddress(e.target.value)}
                                placeholder="0x..."
                            />
                        </div>
                        <p style={{ fontSize: '0.8rem', opacity: 0.6 }}>
                            Authorizing a node allows it to perform Node 1 verification and lock user document hashes on-chain.
                        </p>
                        <div style={{ display: 'flex', gap: '1rem', marginTop: 'auto' }}>
                            <button onClick={() => handleVerifierAction('add')} disabled={loading || !verifierAddress} className="btn btn-primary" style={{ flex: 1 }}>
                                Authorize Node
                            </button>
                            <button onClick={() => handleVerifierAction('remove')} disabled={loading || !verifierAddress} className="btn btn-outline" style={{ flex: 1 }}>
                                Revoke Node
                            </button>
                        </div>
                    </div>
                </div>
            </div>

            <div className="glass" style={{ marginTop: '3rem', padding: '2rem', display: 'flex', gap: '2rem', alignItems: 'center' }}>
                <div style={{ fontSize: '2rem' }}>🛡️</div>
                <p style={{ fontSize: '0.9rem', color: 'var(--text-secondary)', margin: 0 }}>
                    <strong>Protocol Guard:</strong> All registry changes are permanent on the Ethereum blockchain. Removing an entity or node will immediately invalidate any future verification attempts through their channels.
                </p>
            </div>
        </div>
    );
};

export default AdminDashboard;
